export const USDollarRevert = value => Number(value.split(",").join(""))
export const USDollar = new Intl.NumberFormat('en-US', {
  style: 'currency',
  currency: 'USD',
  minimumFractionDigits: 0,
});
export const USDollarFormat = (value, option = {}) => new Intl.NumberFormat('en-US', {
  style: 'currency',
  currency: 'USD',
  minimumFractionDigits: 0,
  ...option
}).format(value);
export const capFirstLetter = str => str.charAt(0).toUpperCase() + str.slice(1) 

export const takeNumberOnly = (value) => {
  if (typeof value === 'number') value = value.toString();
  return ~~value.replace(/[^0-9]/g, '');
};
export const addCommas = (num) => num.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
export const removeNonNumeric = (num) => num.toString().replace(/[^0-9]/g, "");

export const convertToDollarFormat = (value, percent) => {
  let formatted = `${Number(~~value).toLocaleString('en')}`;
  if (percent) {
    formatted = formatted + '%';
  } else {
    formatted = '$' + formatted;
  }
  return formatted;
};

export const addPercentageSign = (value) => {
  if (typeof value === 'number') value = value.toString();
  return value + '%';
};

export const convertToPercentage = (
  value,
  addSign = true
) => {
  let formatted = `${Number(~~value)}`;
  let tempArray = formatted.split('');
  if (tempArray.length === 1) {
    tempArray = ['0.', '0', `${tempArray[0]}`];
  } else if (tempArray.length === 2) {
    tempArray = ['0.', `${tempArray[0]}`, `${tempArray[1]}`];
  } else if (tempArray.length === 3) {
    tempArray = [`${tempArray[0]}.`, `${tempArray[1]}`, `${tempArray[2]}`];
  } else if (tempArray.length >= 4) {
    tempArray = [tempArray[0], tempArray[1] + ".", tempArray[2], tempArray[3]];
  }
  if (addSign) return addPercentageSign(tempArray.join(''));
  return tempArray.join('');
};

export const getFirstHalfYearOrLatterHalf = (index, selectedIndex = 0, isFirstSixMonths = true) => {
  if (isFirstSixMonths) {
    return index >= selectedIndex * 12 && index < selectedIndex * 12 + 6;
  } else {
    return index >= selectedIndex * 12 + 6 && index < selectedIndex * 12 + 12;
  }
};
export const calcNewPrincipal = ({
  loanPrincipal,
  repayment,
  interest
}) => {
  return loanPrincipal - (repayment - interest);
};

export const calcInterest = ({
  rate,
  loanPrincipal,
  numberOfPayments = 12
}) => {
  const decimalNumber = parseFloat(convertToPercentage(rate, false)) * 0.01;
  const getFloatRate = parseFloat(decimalNumber.toFixed(4));
  return (getFloatRate / numberOfPayments) * loanPrincipal;
};

export const getSummaryData = ({ paymentDataArray }) => {
  return paymentDataArray.reduce(
    (accumulator, currentValue) => {
      return {
        totalInterestPaid:
          accumulator.totalInterestPaid + currentValue.interestPaid,
        totalPrinciplePaid:
          accumulator.totalInterestPaid + currentValue.principlePaid
      };
    },
    {
      totalInterestPaid: 0,
      totalPrinciplePaid: 0
    }
  );
};

export const getSummary = (data, selectedIndex = 0, isFirstSixMonths = true) => {
  const paymentDataArray = [];
  const monthlyInterestArray = [];
  const monthlyPrincipleArray = [];
  const monthlyNewBlanceArray = [];
  if (data.year) {
    for (let i = 0; i < data.year * 12; i++) {
      const interestPaidMonthly = calcInterest({
        rate: data.interestRate,
        loanPrincipal:
          paymentDataArray.length === 0
            ? data.mortgage - data.downPayment
            : paymentDataArray[i - 1].loanBalance
      });
      const newBalance = calcNewPrincipal({
        loanPrincipal:
          paymentDataArray.length === 0
            ? data.mortgage - data.downPayment
            : paymentDataArray[i - 1].loanBalance,
        repayment: data.monthlyPayment,
        interest: interestPaidMonthly
      });
      monthlyInterestArray.push(Number(interestPaidMonthly.toFixed(2)));
      monthlyPrincipleArray.push(
        Number((data.monthlyPayment - interestPaidMonthly).toFixed(2))
      );
      monthlyNewBlanceArray.push(
        Number(newBalance.toFixed(2)) < 0 ? 0 : Number(newBalance.toFixed(2))
      );
      const paymentData = {
        loanBalance:
          Number(newBalance.toFixed(2)) < 0 ? 0 : Number(newBalance.toFixed(2)),
        principlePaid: Number(
          (data.monthlyPayment - interestPaidMonthly).toFixed(2)
        ),
        interestPaid: Number(interestPaidMonthly.toFixed(2)),
        month: i + 1
      };
      paymentDataArray.push(paymentData);
    }
  }

  // each year

  // calc total from array
  const totalInterestPaid = monthlyInterestArray.reduce((a, c) => a + c, 0);
  const totalPrinciplePaid = monthlyPrincipleArray.reduce((a, c) => a + c, 0);

  const dollarTotalInterestPaid = convertToDollarFormat(totalInterestPaid)
  const dollarTotalPrinciplePaid = convertToDollarFormat(data.mortgage - data.downPayment)
  const dollarPrincipleInterest = convertToDollarFormat(data.mortgage - data.downPayment + totalInterestPaid)
  const dollarPayment = convertToDollarFormat(Math.floor(data.monthlyPayment))
  const paidOffByWhen = data.year + new Date().getFullYear()
  return {
    dollarTotalInterestPaid,
    dollarTotalPrinciplePaid,
    dollarPrincipleInterest,
    dollarPayment,
    paidOffByWhen,
    stackedBarChartData: getStackedBarChartData(data),
    totalInterestPaid,
    totalPrinciplePaid
  }
}

export const getStackedBarChartData = (data) => {
  const stackedBarChartData = []
  if (data.year) {
    const paymentDataArray = [];
    const monthlyInterestArray = [];
    const monthlyPrincipleArray = [];
    const monthlyNewBlanceArray = [];
    const getInterest = (i) => {
      const principalBalance = paymentDataArray.length === 0
        ? data.mortgage - data.downPayment
        : paymentDataArray[i - 1].loanBalance
      const decimalNumber = parseFloat(convertToPercentage(data.interestRate, false)) * 0.01;
      const getFloatRate = parseFloat(decimalNumber.toFixed(4));
      return (getFloatRate / 12) * principalBalance
    }
    const getPrincipal = (interestPaidMonthly, i) => {
      const loanPrincipal =
        paymentDataArray.length === 0
          ? data.mortgage - data.downPayment
          : paymentDataArray[i - 1].loanBalance
      const repayment = data.monthlyPayment
      const interest = interestPaidMonthly
      return loanPrincipal - (repayment - interest);
    }
    for (let i = 0; i < data.year * 12; i++) {
      const interestPaidMonthly = getInterest(i);
      const newBalance = getPrincipal(interestPaidMonthly, i);
      monthlyInterestArray.push(Number(interestPaidMonthly.toFixed(2)));
      monthlyPrincipleArray.push(
        Number((data.monthlyPayment - interestPaidMonthly).toFixed(2))
      );
      monthlyNewBlanceArray.push(
        Number(newBalance.toFixed(2)) < 0 ? 0 : Number(newBalance.toFixed(2))
      );
      const paymentData = {
        loanBalance:
          Number(newBalance.toFixed(2)) < 0 ? 0 : Number(newBalance.toFixed(2)),
        principlePaid: Number(
          (data.monthlyPayment - interestPaidMonthly).toFixed(2)
        ),
        interestPaid: Number(interestPaidMonthly.toFixed(2)),
        month: i + 1
      };
      paymentDataArray.push(paymentData);
    }
    const result = []
    paymentDataArray.reduce((pre, cur, i) => {
      const principle = cur.principlePaid
      const interest = cur.interestPaid
      if (parseFloat(cur.month / 12) % 1 === 0) {
        result.push({
          year: cur.month / 12 + new Date().getFullYear(),
          principle: pre[pre.length - 1].principle + principle,
          interest: pre[pre.length - 1].interest + interest,
          balance: cur.loanBalance,
        })
        pre.push({
          year: 0,
          principle: 0,
          interest: 0,
          balance: 0,
        })
      } else {
        pre.push({
          year: cur.month / 12 + new Date().getFullYear(),
          principle: pre.length ? pre[pre.length - 1].principle + principle : principle,
          interest: pre.length ? pre[pre.length - 1].interest + interest : interest,
          balance: cur.loanBalance,
        })
      }
      return pre
    }, stackedBarChartData)
    return result
  }
}

export const numberToMonth = value => {
  const month = ["January","February","March","April","May","June","July","August","September","October","November","December"];
  return month[value]
}

export const simpleTheDate = value => {
  return new Intl.DateTimeFormat('en-US').format(value)
}

export const upperCaseFirstLetter = value => {
  return value[0].toUpperCase() + value.slice(1)
}

class Tooltip {
  constructor(self, innerHTML) {
    this.tooltip = document.body?.querySelector("#tooltip")
    if (!this.tooltip) {
      this.tooltip = document.createElement("div")
      this.tooltip.setAttribute("id", "tooltip")
      this.tooltip.innerHTML = innerHTML ? innerHTML : `
        <div class="year"></div>
          <div class="content">
            <div class="dot"></div>
            <div class="text"></div>
          </div> 
        </div>
      `
      document.body.appendChild(this.tooltip)
    }
    self.tooltip = this.tooltip
  }
  getTooltip() {
    return this.tooltip
  }
  move = (e) => {
    this.tooltip.style.left = e.clientX + 10 + "px"
    this.tooltip.style.top = e.clientY + 10 + "px"
  }
  hide = e => {
    this.tooltip.style.opacity = 0
    this.tooltip.style.display = "none"
  }
  show = e => {
    this.tooltip.style.display = "flex"
    this.tooltip.style.opacity = 1
  }

}
export const handleTooltip = (self) => {
  return new Tooltip(self)
}

class EventT extends EventTarget {
  constructor() {
    super()
  }
  dispatch(name, detail) {
    const event = new CustomEvent(name, { detail: detail });
    this.dispatchEvent(event);
  }
}

export function globImport(name) {
  return import(name);
}
